from dataclasses import dataclass
from typing import Any

@dataclass
class SlotDefinition:
    key: str
    expected_type: type
    writer_id: str | None  # None = any agent may write
    required: bool = False

class TypedBlackboard(Blackboard):
    """
    Blackboard with schema validation.
    Raises ValueError on type mismatch or unauthorized write.
    """
    def __init__(self, schema: list[SlotDefinition]):
        super().__init__()
        self._schema = {s.key: s for s in schema}

    def write(self, key: str, value: Any, written_by: str):
        defn = self._schema.get(key)
        if defn is None:
            raise ValueError(f"Unknown slot '{key}' — add it to the schema first")
        if not isinstance(value, defn.expected_type):
            raise TypeError(
                f"Slot '{key}' expects {defn.expected_type.__name__}, "
                f"got {type(value).__name__}"
            )
        if defn.writer_id is not None and written_by != defn.writer_id:
            raise PermissionError(
                f"Only '{defn.writer_id}' may write to slot '{key}'"
            )
        super().write(key, value, written_by)

    def validate_required_slots(self) -> list[str]:
        """Return a list of required slots that have not been written yet."""
        missing = []
        for key, defn in self._schema.items():
            if defn.required and not self.has(key):
                missing.append(key)
        return missing

# Example schema:
schema = [
    SlotDefinition("research.findings", str, writer_id="researcher", required=True),
    SlotDefinition("critique.verdict", dict, writer_id="critic", required=True),
    SlotDefinition("final.report", str, writer_id="writer", required=True),
]
tbb = TypedBlackboard(schema)
tbb.write("research.findings", "Key facts found...", written_by="researcher")
missing = tbb.validate_required_slots()
print(missing)  # ["critique.verdict", "final.report"]

# Unauthorized write attempt:
try:
    tbb.write("research.findings", "Malicious data", written_by="bad-agent")
except PermissionError as e:
    print(e)  # Only 'researcher' may write to slot 'research.findings'
